#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd and "--run" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and will timeout.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import sys
import json
import ast
import re

def main():
    event_data = json.load(sys.stdin)

    if event_data.get("tool") != "Edit":
        sys.exit(0)

    params = event_data.get("params", {})
    file_path = params.get("file_path", "")

    if not file_path.endswith(".py"):
        sys.exit(0)

    old_string = params.get("old_string", "")
    new_string = params.get("new_string", "")

    # Check if converting iterative to recursive
    old_is_iterative = is_iterative_traversal(old_string)
    new_is_recursive = has_recursion(new_string)

    if old_is_iterative and new_is_recursive:
        print("BLOCKED: Converting iterative traversal to recursion", file=sys.stderr)
        print("Python recursion limit is ~1000. Deep structures will cause RecursionError.", file=sys.stderr)
        print("Keep iterative approach or add explicit depth limit parameter.", file=sys.stderr)
        sys.exit(2)

    sys.exit(0)

def is_iterative_traversal(code):
    """Detect iterative tree/graph/list traversal patterns."""
    if not code:
        return False
    # Look for common iterative traversal patterns:
    # - worklist/stack/queue with while loop
    # - iteration over children/nodes
    patterns = [
        r'\bworklist\b.*\bwhile\b',
        r'\bwhile\b.*\bworklist\b',
        r'\bstack\b.*\bwhile\b',
        r'\bwhile\b.*\bstack\b',
        r'\bqueue\b.*\bwhile\b',
        r'\bwhile\b.*\bqueue\b',
        r'\bfor\b.*\bchildren\b',
        r'\bfor\b.*\bnodes\b',
        r'\bwhile\b.*\bpop\(',
    ]
    code_normalized = ' '.join(code.split())  # Collapse whitespace for matching
    return any(re.search(pattern, code_normalized, re.IGNORECASE) for pattern in patterns)

def has_recursion(code):
    """Detect recursive function definitions."""
    if not code:
        return False
    try:
        tree = ast.parse(code)
    except SyntaxError:
        return False

    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            func_name = node.name
            # Check if function body contains a call to itself
            for inner in ast.walk(node):
                if isinstance(inner, ast.Call):
                    if isinstance(inner.func, ast.Name) and inner.func.id == func_name:
                        return True
    return False

if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""After Edit/MultiEdit on a line that defines an exported identifier, grep
for all references and feed the list back to Claude so it can update them."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names: set[str] = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, "."],
                capture_output=True, text=True, timeout=5, cwd=ev.get("cwd", ".")
            )
            hits = [l for l in r.stdout.splitlines() if l][:30]
            if hits:
                print(f"REQUIRED FOLLOW-UP: export `{name}` was edited. {len(hits)} references found:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Update each occurrence to match your change. Do not stop until done.", file=sys.stderr)
                return 2
        except Exception:
            pass
    return 0

if __name__ == "__main__":
    sys.exit(main())

