#!/usr/bin/env python3
"""Block git commands that would stage .env files for commit."""
import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") != "Bash":
        return 0

    cmd = (ev.get("tool_input") or {}).get("command", "")

    # Match git add with .env (but not .env.example)
    if re.search(r'\bgit\s+add\b.*\.env(?!\.example)\b', cmd):
        print("CLAUDE.md prohibits committing .env files. Only .env.example should be committed.", file=sys.stderr)
        return 2

    # git commit -a would stage all modified files including .env
    if re.search(r'\bgit\s+commit\b.*\b-a', cmd):
        print("git commit -a would stage .env if modified. Use explicit file paths instead.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After editing Python files, run pytest to catch errors before continuing."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "Write"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    # Only run for Python files
    if not file_path.endswith(".py"):
        return 0

    # Run pytest
    try:
        result = subprocess.run(
            ["python", "-m", "pytest", "-x", "--tb=short"],
            capture_output=True,
            text=True,
            timeout=30,
            cwd=os.environ.get("CLAUDE_PROJECT_DIR", ".")
        )

        if result.returncode != 0:
            print(f"BLOCKING: pytest failures detected after editing {file_path}:", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
            if result.stderr:
                print(result.stderr, file=sys.stderr)
            print("Fix each failure, then re-run tests. Do not stop. Do not ask.", file=sys.stderr)
            return 2
    except subprocess.TimeoutExpired:
        print("BLOCKING: pytest timed out. Fix the hanging test, then continue.", file=sys.stderr)
        return 2
    except Exception:
        # Don't break Claude Code on test infrastructure failures
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())
